import{_ as t,o,c as r,a3 as n}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"51A. Fitness For Work","description":"","frontmatter":{"title":"51A. Fitness For Work","eba":"Mental Health Services 2024-2028","topics":["preliminary","definitions"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/leave/51A-fitness-for-work.md","filePath":"ebas/mental-health/common-terms/leave/51A-fitness-for-work.md"}'),a={name:"ebas/mental-health/common-terms/leave/51A-fitness-for-work.md"};function s(i,e,p,l,h,m){return o(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="_51a-fitness-for-work" tabindex="-1">51A. Fitness For Work <a class="header-anchor" href="#_51a-fitness-for-work" aria-label="Permalink to &quot;51A. Fitness For Work&quot;">​</a></h1><p><strong>51A.1</strong> Definition</p><p>In this clause 51A, Treating Practitioner means any AHPRA Registered Health Practitioner relevant to the fitness for work concern including, where relevant, an AHPRA-registered health practitioner delivering a program (such as the Nursing and Midwifery Health Program Victoria) attended by the Employee, or a psychologist.</p><p><strong>51A.2</strong> Fit for Work</p><p><strong>(a)</strong> The Employer is responsible for providing a workplace that is safe and without risk to health for Employees, so far as is reasonably practicable.</p><p><strong>(b)</strong> Each Employee is responsible for ensuring that they are fit to perform their duties without risk to the safety, health and well-being of themselves and others within the workplace. This responsibility includes compliance with reasonable measures</p><p>put in place by the Employer and any related occupational health and safety requirements.</p><p><strong>51A.3</strong> Addressing concerns about Fitness for Work</p><p><strong>(a)</strong> In the event the Employee&#39;s manager forms a reasonable belief (as defined at subclause 51A.3(b) below) that an Employee may be unfit to perform their duties, the Employer will act in a timely manner to promote physical, mental and emotional health so that Employees can safely undertake and sustain work.</p><p><strong>(b)</strong> In this clause reasonable belief means a belief based on sufficient evidence that supports a conclusion on the balance of probabilities. Nothing in this clause permits an Employer to act contrary to the Health Records Act 2001 (Vic).</p><p><strong>(c)</strong> The Employer will:</p><p><strong>(i)</strong> take all reasonable steps to give the Employee an opportunity to answer any concerns which are the subject of the reasonable belief (which will include the Employer outlining the concern in writing and offering to meet the Employee),</p><p><strong>(ii)</strong> recognise the Employee&#39;s right to have a representative, including a Union representative, at any time when meeting with the Employer</p><p><strong>(iii)</strong> genuinely consider the Employee&#39;s response with a view to promoting physical, mental and emotional health so that Employees can safely undertake and sustain work; and</p><p><strong>(iv)</strong> take these responses into account in considering whether reasonable adjustments can be made in order that the Employee can safely undertake and sustain work.</p><p><strong>51A.4</strong> Report from Treating Practitioner</p><p><strong>(a)</strong> Where, after discussion with the Employee, the Employer continues to have a reasonable belief that the Employee is unfit to perform the duties, the Employer may request the Employee to obtain a report from the Employee&#39;s Treating Practitioner regarding the Employee&#39;s fitness for work, provided that:</p><p><strong>(i)</strong> An Employee receiving treatment from a Treating Practitioner under the Nursing and Midwifery Health Program Victoria shall not be required to obtain a report from that practitioner and may instead obtain the report from a different Treating Practitioner.</p><p><strong>(b)</strong> Where this occurs:</p><p><strong>(i)</strong> the Employer will: <strong>(A)</strong> provide to the Employee, in writing, the concerns and information that forms the basis of the reasonable belief to assist the Employee&#39;s Treating Practitioner to provide a report to the Employee; and <strong>(B)</strong> cover the cost and expenses of the appointment and report; and</p><p><strong>(ii)</strong> The Employee will: <strong>(A)</strong> advise the Employer of the Employee&#39;s Treating Practitioner <strong>(B)</strong> provide a copy of the report to the Employer; and <strong>(C)</strong> meet with the Employer to discuss any report.</p><p><strong>(c)</strong> Report from IME If, on receipt of the report, and (where reasonably practicable) following discussion, the Employer continues to have a reasonable belief that the Employee is unfit for duty, or the Employee does not provide a report from the Treating Practitioner, the Employer may require the Employee to attend an independent medical examination (IME).</p><p>The Employer will:</p><p><strong>(i)</strong> pay for the cost and expenses of the appointment and report</p><p><strong>(ii)</strong> provide a copy of the IME report to the Employee; and</p><p><strong>(iii)</strong> meet with the Employee to discuss any report.</p><p><strong>(d)</strong> Information to Employee before IME Before the Employee attends an IME under subclause 51A.3(c) above, the Employee will be provided with a copy of:</p><p><strong>(i)</strong> the name of the proposed IME; and</p><p><strong>(ii)</strong> any correspondence (including any supporting material) proposed to be sent to the IME.</p><p><strong>(e)</strong> Employee consultation and right to supplement information Before attending an IME, the Employee may:</p><p><strong>(i)</strong> supplement the material to be provided to the IME; and/or</p><p><strong>(ii)</strong> meet with the Employer to consult about the material the Employer proposes to provide the IME. The Employee&#39;s representative may attend the meeting.</p><p><strong>(f)</strong> Relationship to WIRC</p><p><strong>(i)</strong> This sub-clause 51A.4 does not apply to an injury that is the subject of an active WorkCover claim. Matters regarding an Employee&#39;s Fitness for Work regarding an injury that is the subject of a WorkCover claim will be managed in accordance with the WIRC Act including the Employer&#39;s obligation to provide a safe work environment.</p><p><strong>(g)</strong> Relationship to Personal Leave The processes in this clause 51A do not apply to a period of personal leave under clause 38A (Personal Leave) of this Agreement.</p><p><strong>(h)</strong> Safe Work Environment is paramount Nothing in this clause 51A prevents an Employer from taking any reasonable step in the workplace to ensure a safe work environment.</p>',36)])])}const d=t(a,[["render",s]]);export{g as __pageData,d as default};
